-- ============================================================================
-- MotorsportHub — Schéma Supabase (Postgres)
-- À exécuter une fois dans l'éditeur SQL du projet Supabase
-- (Dashboard → SQL Editor → New query → coller ce fichier → Run).
-- ============================================================================

-- ── Tables ──────────────────────────────────────────────────────────────────

create table public.disciplines (
    id integer generated by default as identity primary key,
    slug text not null unique,
    nom text not null,
    emoji text not null default '',
    ordre integer not null default 0
);

create table public.organisateurs (
    id integer generated by default as identity primary key,
    nom text not null unique,
    site_web text
);

create table public.plateaux (
    id integer generated by default as identity primary key,
    slug text not null unique,
    nom text not null,
    description text not null default '',
    annee_creation integer,
    site_web text,
    statut text not null default 'actif' check (statut in ('actif', 'disparu')),
    discipline_id integer not null references public.disciplines (id),
    organisateur_id integer not null references public.organisateurs (id)
);

-- ── Sécurité : lecture publique, écriture interdite ─────────────────────────
-- La clé « anon » embarquée dans le front ne permet que le SELECT.
-- L'écriture se fait via le dashboard Supabase (ou plus tard via l'API .NET
-- avec la clé service_role, qui ne doit JAMAIS être embarquée dans le front).

alter table public.disciplines enable row level security;
alter table public.organisateurs enable row level security;
alter table public.plateaux enable row level security;

create policy "lecture publique" on public.disciplines for select using (true);
create policy "lecture publique" on public.organisateurs for select using (true);
create policy "lecture publique" on public.plateaux for select using (true);

