-- Plateaux
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (1, 'championnat-de-france-ffsa-gt', 'Championnat de France FFSA GT (GT4 France)', 'Le championnat national de Grand Tourisme, disputé avec des voitures de catégorie GT4 (Alpine, Porsche, Mercedes-AMG, Audi, BMW...) sur les grands circuits français comme Le Castellet, Magny-Cours, Nogaro ou Lédenon.', 1997, 'https://www.ffsa.org', 'actif', 1, 2);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (2, 'championnat-de-france-ffsa-tourisme', 'Championnat de France FFSA Tourisme (TC France)', 'Le championnat de France des voitures de tourisme, avec des berlines de course proches de la réglementation TCR. Il partage généralement ses meetings avec le FFSA GT.', null, 'https://www.ffsa.org', 'actif', 1, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (3, 'championnat-de-france-f4', 'Championnat de France F4', 'La formule de promotion monoplace française, gérée par la FFSA Academy au Mans. Véritable tremplin vers le haut niveau, elle a révélé Pierre Gasly, Esteban Ocon, Anthoine Hubert, Théo Pourchaire ou Isack Hadjar.', 2010, 'https://www.ffsa.org', 'actif', 1, 3);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (4, 'porsche-carrera-cup-france', 'Porsche Carrera Cup France', 'La coupe monotype la plus relevée de l''Hexagone : toutes les voitures sont des Porsche 911 GT3 Cup identiques. Les courses ont lieu en lever de rideau de grands événements en France et en Europe.', 1987, null, 'actif', 1, 4);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (5, 'alpine-elf-cup-series', 'Alpine Elf Cup Series', 'Coupe monotype disputée avec l''Alpine A110 Cup, héritière de l''Alpine Elf Europa Cup. Elle met en avant la marque dieppoise sur les circuits français et européens.', 2018, null, 'actif', 1, 5);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (6, 'clio-cup-series', 'Clio Cup Series', 'Coupe monotype historique du sport automobile français, disputée avec la Renault Clio Cup. Formule d''accès réputée pour son excellent rapport coût/plaisir et ses pelotons très disputés.', null, null, 'actif', 1, 6);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (7, 'ultimate-cup-series', 'Ultimate Cup Series', 'Série française d''endurance et de sprint ouverte aux prototypes (LMP3, CN...), aux GT et aux monoplaces, avec des meetings sur les grands circuits français et européens.', 2019, null, 'actif', 1, 7);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (8, 'championnat-de-france-des-rallyes', 'Championnat de France des Rallyes (asphalte)', 'Le championnat de France « asphalte », dont le calendrier s''appuie sur des épreuves mythiques comme le Rallye du Touquet, le Rallye du Var, Antibes ou le Rouergue. Sébastien Loeb et Sébastien Ogier y ont fait leurs armes.', 1967, 'https://www.ffsa.org', 'actif', 2, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (9, 'championnat-de-france-des-rallyes-terre', 'Championnat de France des Rallyes Terre', 'Le pendant « terre » du championnat de France des rallyes, disputé sur des spéciales en terre et gravier (Terre des Causses, Terre de Vaucluse, Cardabelles...). Une excellente école de pilotage sur surface glissante.', null, 'https://www.ffsa.org', 'actif', 2, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (10, 'championnat-de-france-rallycross', 'Championnat de France de Rallycross', 'Courses en sprint sur circuits mixtes terre/asphalte (Lohéac, Dreux, Lessay...), avec des divisions Supercar, Super 1600 et Division 3/4. Le meeting de Lohéac attire chaque année des dizaines de milliers de spectateurs.', 1977, 'https://www.ffsa.org', 'actif', 2, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (11, 'championnat-de-france-de-la-montagne', 'Championnat de France de la Montagne', 'Le championnat des courses de côte : des tracés en montée contre le chronomètre (Mont-Dore, Turckheim...). Il oppose des monoplaces, des protos et des voitures fermées de production.', null, 'https://www.ffsa.org', 'actif', 3, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (12, 'championnat-de-france-des-rallyes-tout-terrain', 'Championnat de France des Rallyes Tout-Terrain', 'Rallyes disputés hors asphalte avec buggys et 4x4 de type cross-country (Plaines et Vallées, Gatinais, Dunes et Marais...). Une discipline qui prépare aux grands rallyes-raids comme le Dakar.', null, 'https://www.ffsa.org', 'actif', 4, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (13, 'championnat-de-france-autocross-sprint-car', 'Championnat de France d''Autocross et Sprint Car', 'Courses en peloton sur circuits en terre fermés, avec des buggys monoplaces (Sprint Car) et des voitures de tourisme préparées (Autocross). Spectacle garanti et épreuves très populaires dans l''Ouest et le Sud-Ouest.', null, 'https://www.ffsa.org', 'actif', 4, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (14, 'championnat-de-france-endurance-tout-terrain', 'Championnat de France d''Endurance Tout-Terrain', 'Épreuves d''endurance hors route de plusieurs heures, façon « Baja » à la française, dont les 24 Heures Tout-Terrain de France sont l''épreuve phare.', null, 'https://www.ffsa.org', 'actif', 4, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (15, 'championnat-de-france-karting', 'Championnat de France de Karting', 'Les championnats de France de karting couvrent toutes les catégories, des Minimes et Cadets jusqu''aux KZ à boîte de vitesses. C''est la porte d''entrée du sport automobile : la quasi-totalité des pilotes professionnels français en sont issus.', null, 'https://www.ffsa.org', 'actif', 5, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (16, 'iame-series-france', 'IAME Series France', 'Série monomarque de karting disputée avec les moteurs IAME (X30). L''une des séries clients les plus fournies de France, avec une finale internationale très convoitée.', null, null, 'actif', 5, 8);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (17, 'championnat-de-france-de-drift', 'Championnat de France de Drift', 'Le championnat national de drift : les pilotes sont jugés sur l''angle, la vitesse et le style de leurs passages en glisse, en runs individuels puis en battles à deux voitures.', null, null, 'actif', 6, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (18, 'championnat-de-france-camions', 'Championnat de France Camions', 'Courses de tracteurs de course de plus de 1 000 chevaux sur circuits, dont le Grand Prix Camions de Nogaro et le Grand Prix de France Camions au Castellet sont les rendez-vous majeurs.', null, 'https://www.ffsa.org', 'actif', 7, 1);
insert into public.plateaux (id, slug, nom, description, annee_creation, site_web, statut, discipline_id, organisateur_id) values (19, 'historic-tour', 'Historic Tour — Championnat de France Historique des Circuits', 'Le championnat de France des voitures historiques de compétition (VHC) sur circuit : monoplaces, protos et tourisme des années 1960 à 1990 se retrouvent sur des plateaux dédiés lors des meetings Historic Tour.', null, 'https://www.ffsa.org', 'actif', 8, 10);

